_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vec2 st = (vUv * 2.0 - 1.0) * vec2(uTexSize.x/uTexSize.y, 1.0);

  vec3 color = vec3(0, 0, 0);
  float luma = 0.5;
  float timeScale = uTime * 0.5;
  vec2 layerSt = st * (cos(timeScale * q3) * 0.6 + 0.8);
  layerSt = multiply(layerSt, rotate2d(cos(timeScale * 0.046 + 5.0) * PI + PI));

  for (int i = 0; i < ITERATIONS; i++) {
    vec2 gridSt = layerSt + vec2(cos(timeScale * 0.026) * 6.0 + 6.0,
                                 cos(timeScale * q4) * 6.0 + 6.0);
    layerSt = multiply(layerSt, rotate2d(-cos(timeScale * 0.0024) * PI + 1.0));

    float depth = (float(i) + 0.5) / float(ITERATIONS);
    float focusDepth = depth - (cos(timeScale * q6) * 0.5 + 0.5) * 0.8 + 0.1;
    float blur = 0.05 + focusDepth * focusDepth * 0.4;

    float chromaticAberration = cos(timeScale * q8) * 0.2 + 0.2;
    float shapeSize = 0.3 + cos(timeScale * 0.148) * 0.2;
    vec3 shapeColor = vec3(
      shape(gridSt - st * chromaticAberration * blur, shapeSize, blur),
      shape(gridSt, shapeSize, blur),
      shape(gridSt + st * chromaticAberration * blur, shapeSize, blur)
    ) * luma;

    layerSt += st * shape(gridSt, shapeSize, 0.5) * cos(timeScale * 0.162) * 0.6;
    layerSt *= cos(timeScale * 0.46) * 0.05 + 1.1;
    color += shapeColor;
    luma *= 0.85;
  }

  ret = vec4(color, 1.0);

  fragColor = ret;
}
